class DiskCache:
    """Disk-based cache with msgpack serialization and timestamp-based expiration."""

    def __init__(self, cache_dir="cache", default_ttl=300):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        self._lock = threading.Lock()
        os.makedirs(cache_dir, exist_ok=True)

    def _get_cache_path(self, key):
        """Generate a safe file path from cache key."""
        hashed = hashlib.sha256(key.encode("utf-8")).hexdigest()
        return os.path.join(self.cache_dir, f"{hashed}.msgpack")

    def _serialize(self, data, ttl):
        """Serialize data with metadata using msgpack."""
        envelope = {
            "created_at": time.time(),
            "ttl": ttl,
            "data": data,
        }
        return msgpack.packb(envelope, use_bin_type=True)

    def _deserialize(self, raw_bytes):
        """Deserialize msgpack bytes back to Python objects."""
        return msgpack.unpackb(raw_bytes, raw=False)

    def _is_expired(self, envelope):
        """Check if a cache entry has expired based on its timestamp."""
        created_at = envelope.get("created_at", 0)
        ttl = envelope.get("ttl", self.default_ttl)
        return (time.time() - created_at) > ttl

    def get(self, key):
        """
        Retrieve cached data for the given key.
        Returns None if not found or expired.
        """
        cache_path = self._get_cache_path(key)

        with self._lock:
            if not os.path.exists(cache_path):
                return None

            try:
                with open(cache_path, "rb") as f:
                    raw_bytes = f.read()

                envelope = self._deserialize(raw_bytes)

                if self._is_expired(envelope):
                    os.remove(cache_path)
                    return None

                return envelope.get("data")

            except (msgpack.exceptions.UnpackException, IOError, OSError) as e:
                app.logger.warning(f"Cache read error for key '{key}': {e}")
                try:
                    os.remove(cache_path)
                except OSError:
                    pass
                return None

    def set(self, key, data, ttl=None):
        """Store data in cache with the specified TTL."""
        if ttl is None:
            ttl = self.default_ttl

        cache_path = self._get_cache_path(key)

        with self._lock:
            try:
                serialized = self._serialize(data, ttl)
                # Write atomically using temp file + rename
                tmp_path = cache_path + ".tmp"
                with open(tmp_path, "wb") as f:
                    f.write(serialized)
                os.replace(tmp_path, cache_path)
            except (msgpack.exceptions.PackException, IOError, OSError) as e:
                app.logger.error(f"Cache write error for key '{key}': {e}")
                try:
                    os.remove(tmp_path)
                except OSError:
                    pass

    def delete(self, key):
        """Remove a specific key from the cache."""
        cache_path = self._get_cache_path(key)
        with self._lock:
            try:
                if os.path.exists(cache_path):
                    os.remove(cache_path)
                    return True
            except OSError as e:
                app.logger.warning(f"Cache delete error for key '{key}': {e}")
            return False

    def clear(self):
        """Remove all cache entries."""
        with self._lock:
            count = 0
            for filename in os.listdir(self.cache_dir):
                if filename.endswith(".msgpack"):
                    try:
                        os.remove(os.path.join(self.cache_dir, filename))
                        count += 1
                    except OSError:
                        pass
            return count

    def cleanup_expired(self):
        """Remove all expired cache entries."""
        with self._lock:
            removed = 0
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                filepath = os.path.join(self.cache_dir, filename)
                try:
                    with open(filepath, "rb") as f:
                        envelope = self._deserialize(f.read())
                    if self._is_expired(envelope):
                        os.remove(filepath)
                        removed += 1
                except (msgpack.exceptions.UnpackException, IOError, OSError):
                    try:
                        os.remove(filepath)
                        removed += 1
                    except OSError:
                        pass
            return removed

    def stats(self):
        """Get cache statistics."""
        total = 0
        expired = 0
        total_size = 0

        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                filepath = os.path.join(self.cache_dir, filename)
                try:
                    total_size += os.path.getsize(filepath)
                    with open(filepath, "rb") as f:
                        envelope = self._deserialize(f.read())
                    total += 1
                    if self._is_expired(envelope):
                        expired += 1
                except (msgpack.exceptions.UnpackException, IOError, OSError):
                    pass

        return {
            "total_entries": total,
            "expired_entries": expired,
            "active_entries": total - expired,
            "total_size_bytes": total_size,
        }


# Initialize the cache
cache = DiskCache(cache_dir="api_cache", default_ttl=300)


def cached_response(ttl=None, key_prefix=""):
    """
    Decorator to cache Flask route responses.
    Builds cache key from request method, path, and query string.
    """

    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Build cache key from request details
            cache_key_parts = [
                key_prefix,
                request.method,
                request.path,
                request.query_string.decode("utf-8"),
            ]
            if request.is_json and request.data:
                cache_key_parts.append(request.data.decode("utf-8"))

            cache_key = "|".join(cache_key_parts)

            # Try to get from cache
            cached_data = cache.get(cache_key)
            if cached_data is not None:
                app.logger.info(f"Cache HIT for {request.path}")
                response = jsonify(cached_data)
                response.headers["X-Cache"] = "HIT"
                return response

            # Cache miss - call the actual function
            app.logger.info(f"Cache MISS for {request.path}")
            result = f(*args, **kwargs)

            # If the function returns a dict or list, cache it
            if isinstance(result, (dict, list)):
                cache.set(cache_key, result, ttl=ttl)
                response = jsonify(result)
                response.headers["X-Cache"] = "MISS"
                return response

            return result

        return decorated_function

    return decorator


